# sync_all.ps1
# Overwrite core project files with the latest version
# Run this from C:\CV-Pro\Computer-Vision (same folder as main.py)

$files = @{}

$files["main.py"] = ""

$files["config.py"] = ""

$files["requirements.txt"] = "b3BlbmN2LXB5dGhvbj09NC4xMC4wLjg0Cm1lZGlhcGlwZT09MC4xMC4xNApudW1weT09MS4yNi40CnNjaXB5PT0xLjEzLjEKdWx0cmFseXRpY3M9PTguMy4yOAo="

$files["src/utils.py"] = ""

$files["src/face_analytics.py"] = ""

$files["src/arm_pose.py"] = ""


foreach ($key in $files.Keys) {
    $winPath = $key -replace "/", "\"
    $dir = Split-Path $winPath -Parent
    if ($dir -and -not (Test-Path $dir)) {
        New-Item -ItemType Directory -Path $dir -Force | Out-Null
    }
    $bytes = [System.Convert]::FromBase64String($files[$key])
    [System.IO.File]::WriteAllBytes($winPath, $bytes)
    Write-Host ("Written: " + $winPath + " (" + $bytes.Length + " bytes)")
}

if (-not (Test-Path "src")) { New-Item -ItemType Directory -Path "src" -Force | Out-Null }
New-Item -ItemType File -Path "src\__init__.py" -Force | Out-Null
Write-Host "Written: src\__init__.py (0 bytes)"

Get-ChildItem -Recurse -Directory -Filter "__pycache__" -ErrorAction SilentlyContinue | Remove-Item -Recurse -Force -ErrorAction SilentlyContinue

$check = Select-String -Path "src\face_analytics.py","src\arm_pose.py" -Pattern "NotImplementedError" -ErrorAction SilentlyContinue
if ($check) {
    Write-Host ""
    Write-Host "[WARNING] NotImplementedError still found in:" -ForegroundColor Red
    $check | ForEach-Object { Write-Host ("  " + $_.Path + ":" + $_.LineNumber) -ForegroundColor Red }
} else {
    Write-Host ""
    Write-Host "[OK] All files synced successfully. You can run: python main.py" -ForegroundColor Green
}